using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args.Length > 0 ? args[0] : "../build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD ERRORS ===");
var errors = new List<(string Project, string File, int Line, int Col, string Code, string Message, string Subcategory)>();
var warnings = new List<(string Project, string File, int Line, int Col, string Code, string Message)>();

build.VisitAllChildren<Error>(e =>
{
    var project = "";
    var node = e.Parent;
    while (node != null)
    {
        if (node is Project p) { project = p.Name; break; }
        node = node.Parent;
    }
    errors.Add((project, e.File ?? "", e.LineNumber, e.ColumnNumber, e.Code ?? "", e.Text ?? "", e.Subcategory ?? ""));
});

build.VisitAllChildren<Warning>(w =>
{
    var project = "";
    var node = w.Parent;
    while (node != null)
    {
        if (node is Project p) { project = p.Name; break; }
        node = node.Parent;
    }
    warnings.Add((project, w.File ?? "", w.LineNumber, w.ColumnNumber, w.Code ?? "", w.Text ?? ""));
});

// Group errors by project
var errorsByProject = errors.GroupBy(e => e.Project).OrderBy(g => g.Key);
foreach (var group in errorsByProject)
{
    Console.WriteLine($"\n--- Project: {group.Key} ---");
    foreach (var e in group)
    {
        Console.WriteLine($"  [{e.Code}] {e.File}({e.Line},{e.Col}): {e.Message}");
    }
}

Console.WriteLine($"\n\n=== SUMMARY ===");
Console.WriteLine($"Total errors: {errors.Count}");
Console.WriteLine($"Total warnings: {warnings.Count}");
Console.WriteLine($"Projects with errors: {errorsByProject.Count()}");

// Show project dependency info
Console.WriteLine("\n=== PROJECT REFERENCES (dependency graph) ===");
build.VisitAllChildren<Project>(p =>
{
    var refs = new List<string>();
    p.VisitAllChildren<Item>(item =>
    {
        if (item.Name == "ProjectReference")
        {
            refs.Add(item.Text);
        }
    });
    if (refs.Count > 0)
    {
        Console.WriteLine($"\n  {p.Name} references:");
        foreach (var r in refs.Distinct())
            Console.WriteLine($"    -> {r}");
    }
});

// Check for MSB3202 (project not found) or MSB4236 etc.
Console.WriteLine("\n=== DEPENDENCY / CASCADING ERROR ANALYSIS ===");
var projectsWithErrors = errorsByProject.Select(g => g.Key).ToHashSet();
// Find projects that failed due to a dependency failure
var cascadeErrors = errors.Where(e =>
    e.Code == "MSB3202" || e.Code == "MSB4236" ||
    e.Message.Contains("could not be resolved") ||
    e.Message.Contains("referenced by") ||
    e.Code == "CS0246" || e.Code == "CS0234" ||
    e.Code == "CS0012"
).ToList();

Console.WriteLine("\nPotential cascading/dependency errors:");
foreach (var e in cascadeErrors)
    Console.WriteLine($"  [{e.Code}] in {e.Project}: {e.Message}");

// Show all warnings that might be relevant
Console.WriteLine("\n=== RELEVANT WARNINGS ===");
foreach (var w in warnings.Where(w => w.Code.StartsWith("CS") || w.Code.StartsWith("MSB") || w.Code.StartsWith("NU")))
{
    Console.WriteLine($"  [{w.Code}] {w.Project} - {w.File}({w.Line},{w.Col}): {w.Message}");
}

